package pratica.na.metodos.objeto.orientacao.domain;public class Student {    public String notaStudent(double nota1, double nota2, double nota3) {        double mediaStudent = (nota1 + nota2 + nota3) / 3;        if (mediaStudent >= 7)            System.out.println(String.format("Aprovado, parabéns! Sua média foi de %.1f pontos", mediaStudent));        else if (mediaStudent < 6.9 && mediaStudent > 5)            System.out.println(String.format("Recuperação, sua média foi de %.1f pontos", mediaStudent));        else if (mediaStudent < 5 && mediaStudent > 0)            System.out.println(String.format("Recuperação, sua média foi de %.1f pontos", mediaStudent));        return "Nota invalida";    }}